    state.push_c_function(gctm)?;
    // C: lua_setfield(L, -2, "__gc");
    state.set_field(-2, b"__gc")?;
    // C: lua_setmetatable(L, -2);
    state.set_metatable(-2)?;
    Ok(())
}

