    // C: static const int optsnum[] = {LUA_GCSTOP, LUA_GCRESTART, ...};
    static OPTS_NUM: &[GcOp] = &[
        GcOp::Stop, GcOp::Restart, GcOp::Collect,
        GcOp::Count, GcOp::Step, GcOp::SetPause, GcOp::SetStepMul,
