437	    /// Stop-the-world full collect. Marks every reachable object from
438	    /// `roots`, then sweeps white (unreachable) boxes from the allgc chain.
439	    pub fn full_collect(&self, roots: &dyn Trace) {
440	        if self.paused.get() {
441	            return;
442	        }
443	        self.state.set(GcState::Collecting);
444	
445	        // ── Mark phase ──────────────────────────────────────────────────
446	        let mut marker = Marker::new();
447	        // Reset all colors to White first (we're stop-the-world; no
448	        // incremental state to preserve).
449	        let mut cursor = self.head.get();
450	        while let Some(ptr) = cursor {
451	            // SAFETY: every entry in the allgc chain is a valid GcBox.
452	            let header = unsafe { &(*ptr.as_ptr()).header };
453	            header.color.set(Color::White);
454	            cursor = header.next.get();
455	        }
456	
457	        // Trace from roots.
458	        roots.trace(&mut marker);
459	
460	        // Drain the gray queue.
461	        while let Some(gray_ptr) = marker.gray_queue.pop() {
462	            // SAFETY: gray_queue only ever contains pointers added via
463	            // Marker::mark, which read them from valid Gc<T> handles.
464	            unsafe {
465	                let bx = gray_ptr.as_ref();
466	                bx.header.color.set(Color::Black);
467	                bx.value.trace(&mut marker);
468	            }
469	        }
470	
471	        // ── Sweep phase ─────────────────────────────────────────────────
472	        // Walk allgc; drop white boxes, keep black. Reset black→white for
473	        // next cycle.
474	        let mut prev_next: &Cell<Option<NonNull<GcBox<dyn Trace>>>> = &self.head;
475	        let mut cursor = prev_next.get();
476	        let mut freed_bytes = 0usize;
477	        while let Some(ptr) = cursor {
478	            // SAFETY: cursor walks the allgc chain; every entry is a valid
479	            // GcBox.
480	            let header = unsafe { &(*ptr.as_ptr()).header };
481	            let next = header.next.get();
482	            match header.color.get() {
483	                Color::White => {
484	                    // Unreachable. Unlink, drop, dealloc.
485	                    prev_next.set(next);
486	                    freed_bytes += header.size;
487	                    // SAFETY: ptr is a uniquely-owned NonNull<GcBox<...>>
488	                    // that we are about to drop. After this, nothing else
489	                    // references it.
490	                    unsafe {
491	                        let _ = Box::from_raw(ptr.as_ptr());
492	                    }
493	                }
494	                Color::Black | Color::Gray => {
495	                    header.color.set(Color::White);
496	                    // Advance prev_next to this box's next-cell.
497	                    // SAFETY: same as above.
498	                    prev_next = unsafe { &(*ptr.as_ptr()).header.next };
499	                }
500	            }
501	            cursor = next;
502	        }
503	
504	        self.bytes.set(self.bytes.get().saturating_sub(freed_bytes));
505	        self.threshold
506	            .set(self.bytes.get() * self.pause_multiplier.get() / 100);
507	        self.collections.set(self.collections.get() + 1);
508	        self.state.set(GcState::Idle);
509	    }
