511	    /// Drop every allocation, ignoring reachability. Called at shutdown.
512	    /// After this returns, every outstanding `Gc<T>` is dangling — callers
513	    /// must ensure no `Gc<T>` outlives the `Heap`.
514	    pub fn drop_all(&self) {
515	        let mut cursor = self.head.get();
516	        self.head.set(None);
517	        while let Some(ptr) = cursor {
518	            // SAFETY: same chain invariant as full_collect's sweep.
519	            let next = unsafe { (*ptr.as_ptr()).header.next.get() };
520	            unsafe {
521	                let _ = Box::from_raw(ptr.as_ptr());
522	            }
523	            cursor = next;
524	        }
525	        self.bytes.set(0);
526	    }
527	}
